// Get webhook body
const webhookData = $('Webhook').first().json.body;

// Get dv2 rules from file
const fileData = $input.first().json;
let dv2Rules;
try {
  // The file content comes as binary data, need to parse it
  if (fileData.data) {
    dv2Rules = JSON.parse(Buffer.from(fileData.data, 'base64').toString('utf-8'));
  } else if (fileData.json) {
    dv2Rules = typeof fileData.json === 'string' ? JSON.parse(fileData.json) : fileData.json;
  } else {
    dv2Rules = fileData;
  }
} catch (e) {
  dv2Rules = fileData;
}

return {
  json: {
    staging_tables: webhookData.staging_tables,
    vault_tables_to_create: webhookData.vault_tables_to_create,
    existing_vault_tables: webhookData.existing_vault_tables || [],
    business_keys: webhookData.business_keys || [],
    dv2_rules: dv2Rules
  }
};

