const llmOutput = $input.first().json.text;

let parsed;
try {
  parsed = JSON.parse(llmOutput);
} catch (e) {
  // Try to extract JSON from markdown code fences (complete or unclosed)
  let jsonStr = llmOutput;
  const fenceMatch = llmOutput.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenceMatch) {
    jsonStr = fenceMatch[1].trim();
  } else if (llmOutput.startsWith('```')) {
    // Unclosed fence (truncated output) — strip opening fence
    jsonStr = llmOutput.replace(/^```(?:json)?\s*/, '').trim();
  }

  try {
    parsed = JSON.parse(jsonStr);
  } catch (e2) {
    // Attempt to recover truncated JSON by closing open structures
    let recovered = jsonStr;
    // If truncated mid-string, close the string
    const quoteCount = (recovered.match(/(?<!\\)"/g) || []).length;
    if (quoteCount % 2 !== 0) recovered += '"';
    // Close any open braces/brackets
    const opens = (recovered.match(/[{\[]/g) || []).length;
    const closes = (recovered.match(/[}\]]/g) || []).length;
    // Add missing closing brackets/braces
    for (let i = 0; i < opens - closes; i++) {
      // Determine if we need ] or } by scanning backwards for the last unmatched opener
      const stack = [];
      for (const ch of recovered) {
        if (ch === '{' || ch === '[') stack.push(ch);
        else if (ch === '}' || ch === ']') stack.pop();
      }
      if (stack.length > 0) {
        const last = stack.pop();
        recovered += last === '{' ? '}' : ']';
      }
    }
    try {
      parsed = JSON.parse(recovered);
    } catch (e3) {
      throw new Error('Could not parse LLM output as JSON: ' + llmOutput.substring(0, 300));
    }
  }
}

// Validate structure
if (!parsed.vault_tables || !Array.isArray(parsed.vault_tables)) {
  throw new Error('LLM output missing vault_tables array');
}

for (const table of parsed.vault_tables) {
  if (!table.table_name || !table.table_type || !table.ddl || !table.load_sql) {
    throw new Error('Vault table entry missing required fields: ' + JSON.stringify(table).substring(0, 200));
  }
}

return {
  json: {
    status: 'success',
    vault_tables: parsed.vault_tables
  }
};

